from langchain_community.vectorstores import FAISS
from langchain_openai import OpenAIEmbeddings
from langchain_core.documents import Document

embedder = OpenAIEmbeddings(model="text-embedding-3-small")

def build_multimodal_index(captioned_images: list[dict]) -> FAISS:
    docs = [
        Document(
            page_content=img["caption"],
            metadata={
                "image_path": img["path"],
                "page": img["page"],
                "source_pdf": img["source_pdf"],
            },
        )
        for img in captioned_images
    ]
    return FAISS.from_documents(docs, embedder)

def retrieve_images(
    query: str,
    index: FAISS,
    k: int = 3,
) -> list[Document]:
    return index.similarity_search(query, k=k)

def answer_with_images(
    question: str,
    retrieved_docs: list[Document],
) -> str:
    """Pass retrieved images + captions to a vision LLM for a grounded answer."""
    content = [{"type": "text", "text": f"Question: {question}\n\nContext images:"}]

    for doc in retrieved_docs:
        image_path = doc.metadata["image_path"]
        b64 = image_to_base64(image_path)
        ext = image_path.rsplit(".", 1)[-1].lower()
        mime = {"jpg": "image/jpeg", "jpeg": "image/jpeg"}.get(ext, "image/png")

        content.append({
            "type": "text",
            "text": f"Caption: {doc.page_content}"
        })
        content.append({
            "type": "image_url",
            "image_url": {"url": f"data:{mime};base64,{b64}"},
        })

    content.append({
        "type": "text",
        "text": "Answer the question using the images and captions above. Be specific."
    })

    msg = vision_llm.invoke([HumanMessage(content=content)])
    return msg.content.strip()

# Full pipeline
def multimodal_rag(question: str, index: FAISS) -> str:
    docs = retrieve_images(question, index, k=3)
    return answer_with_images(question, docs)

from langchain_openai import ChatOpenAI
from langchain_core.messages import HumanMessage

vision_llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)

def colpali_rag(question: str, RAG) -> str:
    results = RAG.search(question, k=3)

    content = [{"type": "text", "text": f"Question: {question}\n\nRelevant document pages:"}]
    for r in results:
        content.append({
            "type": "image_url",
            "image_url": {"url": f"data:image/png;base64,{r['base64']}"},
        })
    content.append({
        "type": "text",
        "text": "Answer the question precisely using the pages shown above."
    })

    return vision_llm.invoke([HumanMessage(content=content)]).content
